mapper.insert:
insert into knowledge_base(
  tenant_id, course_id, name, description, status, del_flag, create_by, create_time, remark
) values (
  #{tenantId}, #{courseId}, #{name}, #{description}, #{status}, '0', #{createBy}, now(), #{remark}
)

insert into knowledge_base_version(
  tenant_id, knowledge_base_id, version_no, status, chunk_count,
  chunk_strategy_version, retrieval_strategy_version,
  del_flag, create_by, create_time, remark
) values (
  #{tenantId}, #{knowledgeBaseId}, #{versionNo}, #{status}, #{chunkCount},
  #{chunkStrategyVersion}, #{retrievalStrategyVersion},
  '0', #{createBy}, now(), #{remark}
)

insert into knowledge_base_version_document(
  tenant_id, knowledge_base_version_id, document_id, document_version_id,
  del_flag, create_by, create_time, remark
) values (
  #{tenantId}, #{knowledgeBaseVersionId}, #{documentId}, #{documentVersionId},
  '0', #{createBy}, now(), #{remark}
)
